);

const Default = () => <DataTable
    columns={DEFAULT_COLUMNS}
    data={ALL_ROWS}
    skeleton={false}
    rowsPerPage={4}
    withCheckbox={false}
    textRowsSelected="itens selecionados" />;

const Loading = () => <DataTable
    columns={DEFAULT_COLUMNS}
    data={[]}
    skeleton
    rowsPerPage={4}
    withCheckbox={false}
    textRowsSelected="itens selecionados" />;

const Empty = () => <DataTable
    columns={DEFAULT_COLUMNS}
    data={[]}
    skeleton={false}
    rowsPerPage={4}
    withCheckbox={false}
    textRowsSelected="itens selecionados" />;

const WithServerSideSearch = () => {
    const [query, setQuery] = useState("");
    const [isLoading, setIsLoading] = useState(false);

    const filtered = ALL_ROWS.filter((row) =>
      Object.values(row).some((val) =>
        String(val).toLowerCase().includes(query.toLowerCase()),
      ),
    );

    const handleSearch = (value: string) => {
      setIsLoading(true);
      setTimeout(() => {
        setQuery(value);
        setIsLoading(false);
      }, 600);
    };

    return (
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            <p style={{ fontSize: 12, color: "#666" }}>Query atual: <strong>"{query}"</strong>— {filtered.length}{" "}resultado(s)
                        </p>
            <DataTable
                columns={DEFAULT_COLUMNS}
                rowsPerPage={4}
                withCheckbox={false}
                textRowsSelected="itens selecionados"
                data={filtered}
                skeleton={isLoading}
                onSearch={handleSearch} />
        </div>
    );
};

const WithServerSideSort = () => {
    const [sortState, setSortState] = useState<SortState | null>(null);
    const [isLoading, setIsLoading] = useState(false);

    const sorted = (() => {
      if (!sortState || sortState.direction === "default") return ALL_ROWS;

      const key = DEFAULT_COLUMNS[sortState.columnIndex]?.key;
      if (!key) return ALL_ROWS;

      return [...ALL_ROWS].sort((a, b) => {
        const aVal = String(a[key as keyof typeof a]);
        const bVal = String(b[key as keyof typeof b]);
        return sortState.direction === "asc"
          ? aVal.localeCompare(bVal)
          : bVal.localeCompare(aVal);
      });
    })();

    const handleSort = (sort: SortState) => {
      setIsLoading(true);
      setTimeout(() => {
        setSortState(sort);
        setIsLoading(false);
      }, 400);
    };

    const directionLabel: Record<string, string> = {
      asc: "crescente",
      desc: "decrescente",
      default: "padrão",
    };

    return (
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            <p style={{ fontSize: 12, color: "#666" }}>
                {sortState
                  ? `Ordenando por coluna ${sortState.columnIndex} (${DEFAULT_COLUMNS[sortState.columnIndex]?.label}) — ${directionLabel[sortState.direction]}`
                  : "Clique em um cabeçalho de coluna para ordenar"}
            </p>
            <DataTable
                columns={DEFAULT_COLUMNS}
                rowsPerPage={4}
                withCheckbox={false}
                textRowsSelected="itens selecionados"
                data={sorted}
                skeleton={isLoading}
                onSort={handleSort} />
        </div>
    );
};

const WithSearchAndSort = () => {
    const [query, setQuery] = useState("");
    const [sortState, setSortState] = useState<SortState | null>(null);
    const [isLoading, setIsLoading] = useState(false);

    const processedData = (() => {
      let result = ALL_ROWS.filter((row) =>
        Object.values(row).some((val) =>
          String(val).toLowerCase().includes(query.toLowerCase()),
        ),
      );

      if (sortState && sortState.direction !== "default") {
        const key = DEFAULT_COLUMNS[sortState.columnIndex]?.key;
        if (key) {
          result = [...result].sort((a, b) => {
            const aVal = String(a[key as keyof typeof a]);
            const bVal = String(b[key as keyof typeof b]);
            return sortState.direction === "asc"
              ? aVal.localeCompare(bVal)
              : bVal.localeCompare(aVal);
          });
        }
      }
      return result;
    })();

    const simulateApiCall = (fn: () => void) => {
      setIsLoading(true);
      setTimeout(() => {
        fn();
        setIsLoading(false);
      }, 500);
    };

    return (
        <DataTable
            columns={DEFAULT_COLUMNS}
            rowsPerPage={4}
            withCheckbox={false}
            textRowsSelected="itens selecionados"
            data={processedData}
            skeleton={isLoading}
            onSearch={(value) => simulateApiCall(() => setQuery(value))}
            onSort={(sort) => simulateApiCall(() => setSortState(sort))} />
    );
};

const WithCheckboxAndBulkActions = () => {
    const [selectedIds, setSelectedIds] = useState<string[]>([]);

    return (
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            <p style={{ fontSize: 12, color: "#666" }}>IDs selecionados:{" "}
                <strong>[{selectedIds.join(", ") || "nenhum"}]</strong>
            </p>
            <DataTable
                columns={DEFAULT_COLUMNS}
                data={ALL_ROWS}
                skeleton={false}
                rowsPerPage={4}
                withCheckbox
                textRowsSelected="itens selecionados"
                headerSelectedChildren={(<>
                  <Button
                    size="md"
                    variant="secondary"
                    onClick={() => alert("Exportar selecionados")}
                  >
                    Exportar
                  </Button>
                  <Button
                    size="md"
                    variant="primary"
                    onClick={() => alert("Excluir selecionados")}
                  >
                    Excluir
                  </Button>
                </>)}
                onSelectedRowsChange={setSelectedIds} />
        </div>
    );
};

const WithExternalSelectionControl = () => {
    const updaterRef = useRef<((ids: string[]) => void) | null>(null);

    return (
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            <div style={{ display: "flex", gap: 8 }}>
                <Button
                    size="md"
                    variant="secondary"
